# Worker Bindings

Bindings connect Workers to Cloudflare services via zero-latency references configured in `wrangler.toml` and accessed through the `env` parameter.

## KV Namespace Binding

```toml
[[kv_namespaces]]
binding = "MY_KV"              # env.MY_KV in Worker code
id = "abc123"                   # production namespace ID
preview_id = "def456"           # preview namespace ID (wrangler dev)
```

```typescript
// TypeScript type: KVNamespace
const value = await env.MY_KV.get('key');
await env.MY_KV.put('key', 'value');
```

## R2 Bucket Binding

```toml
[[r2_buckets]]
binding = "MY_BUCKET"           # env.MY_BUCKET
bucket_name = "my-bucket"       # production bucket
preview_bucket_name = "preview" # preview bucket (wrangler dev)
```

```typescript
// TypeScript type: R2Bucket
const object = await env.MY_BUCKET.get('file.txt');
await env.MY_BUCKET.put('file.txt', 'content');
```

## D1 Database Binding

```toml
[[d1_databases]]
binding = "DB"                  # env.DB
database_name = "my-database"   # database name
database_id = "xxxx-yyyy"       # database UUID
```

```typescript
// TypeScript type: D1Database
const { results } = await env.DB.prepare('SELECT * FROM users').all();
```

## Queue Bindings

```toml
# Producer (send messages)
[[queues.producers]]
binding = "MY_QUEUE"            # env.MY_QUEUE
queue = "my-queue"              # queue name

# Consumer (receive messages)
[[queues.consumers]]
queue = "my-queue"
max_batch_size = 10
max_batch_timeout = 30
```

```typescript
// Producer
await env.MY_QUEUE.send({ type: 'email', to: 'user@example.com' });

// Consumer handler
export default {
  async queue(batch: MessageBatch, env: Env) {
    for (const msg of batch.messages) {
      console.log(msg.body);
      msg.ack();
    }
  },
};
```

## Service Bindings (Worker-to-Worker)

```toml
[[services]]
binding = "AUTH_SERVICE"        # env.AUTH_SERVICE
service = "auth-worker"         # target worker name
```

```typescript
// Call another Worker directly (no network hop)
const response = await env.AUTH_SERVICE.fetch(
  new Request('https://auth/verify', {
    method: 'POST',
    body: JSON.stringify({ token }),
  })
);
```

## Environment Variables

```toml
# Plain text variables
[vars]
API_URL = "https://api.example.com"
ENVIRONMENT = "production"
```

```bash
# Encrypted secrets (not in wrangler.toml)
wrangler secret put API_KEY
```

```typescript
// Both accessed the same way
const apiUrl = env.API_URL;    // string
const apiKey = env.API_KEY;    // string
```

## AI Binding

```toml
[ai]
binding = "AI"                  # env.AI
```

```typescript
const result = await env.AI.run('@cf/meta/llama-3.1-8b-instruct', {
  messages: [{ role: 'user', content: 'Hello' }],
});
```

## Env Type Definition

Define the full `Env` interface for TypeScript:

```typescript
export interface Env {
  // KV
  MY_KV: KVNamespace;
  // R2
  MY_BUCKET: R2Bucket;
  // D1
  DB: D1Database;
  // Queue
  MY_QUEUE: Queue;
  // Service
  AUTH_SERVICE: Fetcher;
  // AI
  AI: Ai;
  // Variables
  API_URL: string;
  API_KEY: string;
}
```
